ValidationRule.errorConditionFormula:
OR(
    AND(
        ISPICKVAL(RES_Identification_Type__c, "ZIT01"),
        NOT(
            REGEX(RES_Identification_Number__c, "^1[0-9]{9}$")
        )
    ),
    AND(
        ISPICKVAL(RES_Identification_Type__c, "ZIT02"),
        NOT(
            REGEX(RES_Identification_Number__c, "^2[0-9]{9}$")
        )
    ),
				AND(
        ISPICKVAL(RES_Identification_Type__c, "ZIT03"),
        NOT(
          REGEX(RES_Identification_Number__c , "^[a-zA-Z0-9]{1,20}$")
        )
    )
)
